export type CardCategory = "Trading Cards" | "Sports Cards" | "Gaming Cards";

export interface Card {
  id: string;
  title: string;
  description: string;
  price: number;
  imageUrl: string;
  category: CardCategory;
  seller: string;
  condition: "Mint" | "Near Mint" | "Excellent" | "Good" | "Played";
  featured?: boolean;
}

export const mockCards: Card[] = [
  {
    id: "1",
    title: "1st Edition Charizard Holographic",
    description: "The holy grail of Pokémon card collecting. Base set, shadowless.",
    price: 150000,
    imageUrl: "https://images.unsplash.com/photo-1613771404721-1f92d799e49f?w=800&q=80",
    category: "Gaming Cards",
    seller: "AshKetchum99",
    condition: "Near Mint",
    featured: true,
  },
  {
    id: "2",
    title: "Black Lotus - Alpha Edition",
    description: "The most iconic Magic: The Gathering card ever printed.",
    price: 500000,
    imageUrl: "https://images.unsplash.com/photo-1593814681464-eef5af2b0628?w=800&q=80",
    category: "Gaming Cards",
    seller: "PlaneswalkerPro",
    condition: "Excellent",
    featured: true,
  },
  {
    id: "3",
    title: "Michael Jordan 1986 Fleer Rookie",
    description: "Iconic rookie card of the greatest basketball player of all time.",
    price: 75000,
    imageUrl: "https://images.unsplash.com/photo-1628193883072-a08336696b9d?w=800&q=80",
    category: "Sports Cards",
    seller: "HoopsCollector",
    condition: "Mint",
    featured: true,
  },
  {
    id: "4",
    title: "Mickey Mantle 1952 Topps",
    description: "One of the most recognizable and valuable baseball cards.",
    price: 1200000,
    imageUrl: "https://images.unsplash.com/photo-1508344928928-7137b29de216?w=800&q=80",
    category: "Sports Cards",
    seller: "VintageDiamond",
    condition: "Good",
  },
  {
    id: "5",
    title: "Blue-Eyes White Dragon 1st Edition",
    description: "Legend of Blue Eyes White Dragon original print.",
    price: 15000,
    imageUrl: "https://images.unsplash.com/photo-1605806616949-1e87b487cb2a?w=800&q=80",
    category: "Trading Cards",
    seller: "KaibaCorp",
    condition: "Mint",
    featured: true,
  },
  {
    id: "6",
    title: "Wayne Gretzky 1979 O-Pee-Chee Rookie",
    description: "The Great One's rookie card.",
    price: 85000,
    imageUrl: "https://images.unsplash.com/photo-1515523110800-9415d13b84a8?w=800&q=80",
    category: "Sports Cards",
    seller: "IceKing",
    condition: "Near Mint",
  },
  {
    id: "7",
    title: "Pikachu Illustrator",
    description: "Extremely rare promo card given to CoroCoro Comic illustration contest winners.",
    price: 900000,
    imageUrl: "https://images.unsplash.com/photo-1613771404784-3a5686aa2be3?w=800&q=80",
    category: "Gaming Cards",
    seller: "PokeMaster",
    condition: "Mint",
  },
  {
    id: "8",
    title: "Honus Wagner T206",
    description: "The Mona Lisa of baseball cards.",
    price: 3000000,
    imageUrl: "https://images.unsplash.com/photo-1629824641195-2df90c41b802?w=800&q=80",
    category: "Sports Cards",
    seller: "MuseumVault",
    condition: "Good",
  }
];

export const categories: CardCategory[] = ["Trading Cards", "Sports Cards", "Gaming Cards"];

import { mockCards, categories, Card } from "@/lib/mock-data";
import Link from "next/link";

export default function BrowsePage({
  searchParams,
}: {
  searchParams: { [key: string]: string | string[] | undefined };
}) {
  const categoryFilter = searchParams.category as string | undefined;
  const searchFilter = searchParams.search as string | undefined;

  let filteredCards = mockCards;

  if (categoryFilter && categoryFilter !== "All") {
    filteredCards = filteredCards.filter((card) => card.category === categoryFilter);
  }

  if (searchFilter) {
    const s = searchFilter.toLowerCase();
    filteredCards = filteredCards.filter(
      (card) =>
        card.title.toLowerCase().includes(s) ||
        card.description.toLowerCase().includes(s)
    );
  }

  return (
    <div className="bg-white">
      <div className="max-w-7xl mx-auto py-8 px-4 sm:px-6 lg:px-8">
        <div className="flex flex-col md:flex-row md:items-center md:justify-between mb-8">
          <h1 className="text-3xl font-extrabold tracking-tight text-slate-900 mb-4 md:mb-0">
            Browse Cards
          </h1>

          <div className="flex flex-wrap gap-2">
            <Link
              href="/browse"
              className={`px-4 py-2 rounded-full text-sm font-medium ${
                !categoryFilter || categoryFilter === "All"
                  ? "bg-indigo-600 text-white"
                  : "bg-slate-100 text-slate-700 hover:bg-slate-200"
              }`}
            >
              All
            </Link>
            {categories.map((cat) => (
              <Link
                key={cat}
                href={`/browse?category=${encodeURIComponent(cat)}`}
                className={`px-4 py-2 rounded-full text-sm font-medium ${
                  categoryFilter === cat
                    ? "bg-indigo-600 text-white"
                    : "bg-slate-100 text-slate-700 hover:bg-slate-200"
                }`}
              >
                {cat}
              </Link>
            ))}
          </div>
        </div>

        {filteredCards.length > 0 ? (
          <div className="grid grid-cols-1 gap-y-10 sm:grid-cols-2 gap-x-6 lg:grid-cols-3 xl:grid-cols-4 xl:gap-x-8">
            {filteredCards.map((card) => (
              <div key={card.id} className="group relative border border-slate-200 rounded-lg p-4 hover:shadow-lg transition-shadow">
                <div className="w-full min-h-64 bg-slate-200 aspect-w-1 aspect-h-1 rounded-md overflow-hidden group-hover:opacity-75 lg:h-64 lg:aspect-none">
                  {/* eslint-disable-next-line @next/next/no-img-element */}
                  <img
                    src={card.imageUrl}
                    alt={card.title}
                    className="w-full h-full object-center object-cover lg:w-full lg:h-full"
                  />
                </div>
                <div className="mt-4">
                  <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-indigo-100 text-indigo-800 mb-2">
                    {card.category}
                  </span>
                  <h3 className="text-sm text-slate-700 font-medium">
                    <Link href={`/browse?card=${card.id}`}>
                      <span aria-hidden="true" className="absolute inset-0" />
                      {card.title}
                    </Link>
                  </h3>
                  <p className="mt-1 text-sm text-slate-500 line-clamp-2">{card.description}</p>
                </div>
                <div className="mt-4 flex items-center justify-between">
                  <p className="text-sm font-medium text-slate-500">Cond: {card.condition}</p>
                  <p className="text-lg font-bold text-slate-900">${card.price.toLocaleString()}</p>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-20">
            <h3 className="mt-2 text-sm font-medium text-slate-900">No cards found</h3>
            <p className="mt-1 text-sm text-slate-500">
              We couldn't find anything matching your current filters.
            </p>
            <div className="mt-6">
              <Link
                href="/browse"
                className="inline-flex items-center px-4 py-2 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
              >
                Clear Filters
              </Link>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

